const requestId = 'REQ-' + Date.now();

return [
  {
    json: {
      request_id: requestId,
      api_base_url: 'https://jsonplaceholder.typicode.com',
      auth_token: 'DEMO_API_TOKEN',
      get_endpoint: '/posts/1',
      post_endpoint: '/posts',
      put_endpoint: '/posts/1',
      post_payload: {
        title: 'New automation record',
        body: 'This record was created from an n8n REST API workflow.',
        userId: 1
      },
      put_payload: {
        id: 1,
        title: 'Updated automation record',
        body: 'This record was updated from an n8n REST API workflow using PUT.',
        userId: 1
      }
    }
  }
];

const setup = $node['Preparar Datos de Prueba'].json;
const getResponse = $node['GET - Consultar Recurso'].json;
const postResponse = $node['POST - Crear Recurso'].json;
const putResponse = $node['PUT - Actualizar Recurso'].json;

const validations = [];

validations.push({
  method: 'GET',
  endpoint: setup.get_endpoint,
  success: !!getResponse.id,
  received_id: getResponse.id || null
});

validations.push({
  method: 'POST',
  endpoint: setup.post_endpoint,
  success: !!postResponse.id,
  created_id: postResponse.id || null
});

validations.push({
  method: 'PUT',
  endpoint: setup.put_endpoint,
  success: putResponse.title === setup.put_payload.title,
  updated_id: putResponse.id || null
});

const allSuccessful = validations.every(item => item.success === true);

return [
  {
    json: {
      success: allSuccessful,
      request_id: setup.request_id,
      api_base_url: setup.api_base_url,
      methods_used: ['GET', 'POST', 'PUT'],
      authentication_type: 'Bearer token header',
      content_type: 'application/json',
      validations,
      get_response_sample: getResponse,
      post_response_sample: postResponse,
      put_response_sample: putResponse
    }
  }
];

const item = $input.first().json;

return [
  {
    json: {
      success: item.success,
      message: item.success
        ? 'REST API integration workflow completed successfully.'
        : 'REST API integration workflow completed with validation issues.',
      request_id: item.request_id,
      api_base_url: item.api_base_url,
      methods_used: item.methods_used,
      authentication_type: item.authentication_type,
      content_type: item.content_type,
      get_request: item.validations.find(v => v.method === 'GET')?.success ? 'completed' : 'failed',
      post_request: item.validations.find(v => v.method === 'POST')?.success ? 'completed' : 'failed',
      put_request: item.validations.find(v => v.method === 'PUT')?.success ? 'completed' : 'failed',
      validations: item.validations
    }
  }
];
